import functools
log = []
def logger(func):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        log.append(f'Calling: {func.__name__}')
        result = func(*args, **kwargs)
        log.append(f'Done: {func.__name__}')
        return result
    return wrapper
@logger
def add(a, b):
    return a + b
add(2, 3)
assert log == ['Calling: add', 'Done: add']
